import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"41. Workload Management And Review","description":"","frontmatter":{"title":"41. Workload Management And Review","eba":"Doctors in Training 2022-2026","topics":["hours","overtime","rosters","staffing","workload"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.md","filePath":"ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.md"}'),i={name:"ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.md"};function n(s,e,l,d,c,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_41-workload-management-and-review" tabindex="-1">41. Workload Management And Review <a class="header-anchor" href="#_41-workload-management-and-review" aria-label="Permalink to &quot;41. Workload Management And Review&quot;">​</a></h1><p><strong>41.1</strong> The provisions of this clause are to be read in conjunction with subclause 35.3 (Roster Design – Safe Hours of Work).</p><p><strong>41.2</strong> Safe Workload</p><p><strong>(a)</strong> The Health Service is obliged by the OHS Act to provide a safe workplace. This includes ensuring that workloads are not unreasonable (including from unrostered overtime). It is recognised that managing workload is necessary to ensure a safe work environment and to ensure that the operational requirements of the Health Service are met.</p><p><strong>(b)</strong> Where a Doctor believes that a Health Service requires the Doctor to perform work in a manner that is unsafe (including from unrostered overtime), the Doctor may first discuss the matter with the Health Service to resolve the issues. If no resolution can be found, the Doctor may utilise the Dispute Resolution Procedure set out in <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> of this Agreement.</p><p><strong>(c)</strong> Nothing in this clause restricts the Association from assisting a Doctor during discussions with the Health Service for the purpose of this clause or utilising the Dispute Resolution Procedure set out in <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> of this Agreement.</p><p><strong>41.3</strong> Assignment of Work</p><p><strong>(a)</strong> The Health Service will ensure that the type and volume of work assigned to the Doctor is reasonable with regard to the Doctor’s skills, abilities, capacity and availability to perform.</p><p><strong>(b)</strong> In considering the work to be assigned to the Doctor, the Health Service must identify the level and type of administrative support available to the Doctor, and must ensure that appropriate levels of administrative support are provided.</p><p><strong>41.4</strong> Consultation</p><p><strong>(a)</strong> The Health Service and Doctor shall consult regularly regarding the Doctor’s workload.</p><p><strong>(b)</strong> The Health Service shall review workloads of Doctors and particular units. The Association or an Ambassador may request to discuss these at any time. Where a formal review is undertaken, that review will be in writing and kept.</p><p><strong>41.5</strong> Review</p><p><strong>(a)</strong> The workload review must be conducted by someone appropriately experienced and who is familiar with the unit and the duties involved.</p><p><strong>(b)</strong> A Doctor may request a workload review at any time (including from unrostered overtime). The purpose of the review is to identify whether the Doctor’s workload is safe and reasonable. Where a review is requested, the Health Service and Doctor shall consult and set out the Doctor’s current duties and responsibilities in writing including each of the following elements where relevant:</p><p><strong>(i)</strong> Direct Public Patient Care and Related Activities – including ward rounds, outpatient clinics, pre-operative assessment, operating time, post-operative care, unit clinical meetings, inter-unit consultations, completion of operation reports, discharge summaries, case mix information and management of waiting lists.</p><p><strong>(ii)</strong> Management Administrative Responsibilities – including roster preparation, budget documents, Health Service reports.</p><p><strong>(iii)</strong> Clinical Research as required by the Health Service.</p><p><strong>(iv)</strong> Practice in a Distant Location – including time taken to travel to and from the distant location.</p><p><strong>(c)</strong> The Health Service and Doctor shall calculate the hours required to perform the tasks and responsibilities set out in writing. This includes taking into account that some aspects of the routine workload occur more frequently than others.</p><p><strong>(d)</strong> The Health Service and Doctor shall review the responsibilities and duties and any amendment to the responsibilities and duties to ensure a safe and reasonable workload shall be recorded in writing.</p><p><strong>41.6</strong> Disputes</p><p>In the event of a dispute as to whether a workload is safe, <a href="/eba/ebas/doctors-in-training/consultation-disputes/12-dispute-resolution-procedure.html">clause 12</a> (Dispute Resolution) shall apply. Neither party will be prejudiced by any alteration to workload to ensure a safe workload before the dispute is resolved.</p><p>Plain language terms: workload, workload review.</p>',24)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
